#include <bits/stdc++.h>
using namespace std;

const int N=3010,mod=1e9+7;

int n,m,f[N][N][2],ans;

void add(int &x,long long y){
    x=(x+y)%mod;
}

int main(){
    scanf("%d%d",&n,&m);
    f[0][0][1]=1;
    for(int i=0;i<n;i++)
        for(int j=0;j<=i;j++){
            add(f[i+1][j][0],1ll*f[i][j][0]*(m-j));
            add(f[i+1][j][1],1ll*f[i][j][0]*j);
            add(f[i+1][j+1][0],1ll*f[i][j][1]*(m-j));
            add(f[i+1][j][1],1ll*f[i][j][1]*j);
        }
    for(int i=0;i<=n;i++)
        add(ans,f[n][i][1]);
    printf("%d",ans);
    return 0;
}
